scwin.f_toExcel = async function () {
  var rowCount = ds_retrieveLine.getRowCount();
  if (rowCount == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_003); // 해당되는 자료가 존재하지 않습니다
    return false;
  }
  let rtn = await $c.win.confirm($p, "Excel로 다운로드 하시겠습니까?");
  if (rtn) {
    let sheetTitle = "CY STOCK 현황";
    const infoArr = [];
    const options = {
      fileName: sheetTitle + ".xls",
      sheetName: sheetTitle
    };
    $c.data.downloadGridViewExcel($p, gr_retrieveLine, options, infoArr);
  }
};

